for (const item of items) {
  const candidate = item.json;
  const role = candidate.position || "Software Engineer";
  const skills = candidate.claimed_skills;
  const background = candidate.past_company_type;

  const systemPrompt = `
  Role: You are a Senior Technical Interviewer for a ${role} position. 
  Your goal is to validate the technical depth of a candidate named ${candidate.candidate_name}.

  CONTEXT:
  The candidate claims expertise in: ${skills}.
  However, their background is from: ${background}.

  TASK:
  Generate 5 advanced technical interview questions (Studi Kasus) to verify if they truly understand the internal workings of the tech stack or just surface-level knowledge.
  Focus on troubleshooting scenarios and architectural trade-offs.

  IMPORTANT: 
  - The questions must be challenging but professional.
  - Provide the output in INDONESIAN language.

  OUTPUT FORMAT (Markdown):
  1. **Topik**: [Nama Topik]
     - **Pertanyaan**: [Studi Kasus Spesifik]
     - **Ekspektasi Jawaban Senior**: [Poin Kunci]
  `;

  item.json.llm_prompt = systemPrompt;
}

return items;
